import React, { useState, useEffect } from 'react';

function App() {
  const [uiMode, setUIMode] = useState('neon'); // neon, dark, compact, fullscreen
  const [angelCreds, setAngelCreds] = useState({ clientCode: '', password: '', totem: '' });
  const [activeBroker, setActiveBroker] = useState('');
  const [brokersConnected, setBrokersConnected] = useState({ angel: false, dhan: false, mt4: false });
  const [pairMode, setPairMode] = useState('auto'); // auto/manual
  const [selectedPair, setSelectedPair] = useState('NIFTY');
  const [isBotActive, setIsBotActive] = useState(false);
  const [realBalance, setRealBalance] = useState('₹0');
  const [positions, setPositions] = useState([]);
  const [status, setStatus] = useState('Ready...');

  const pairs = ['NIFTY', 'BANKNIFTY', 'FINNIFTY', 'EURUSD', 'GBPUSD', 'BTCUSD'];

  // UI Theme Classes
  const themes = {
    neon: 'bg-gradient-to-br from-purple-900 via-pink-900/30 to-indigo-900 text-white shadow-2xl shadow-purple-500/25 backdrop-blur-xl border border-purple-500/30 hover:shadow-purple-500/50 hover:scale-105',
    dark: 'bg-gray-900/90 border border-gray-700/50 shadow-xl shadow-black/50 backdrop-blur-xl hover:shadow-gray-700/40 hover:scale-[1.02]',
    compact: 'bg-black/80 border border-white/10 shadow-lg shadow-black/70 backdrop-blur-2xl p-4 hover:shadow-white/20 hover:scale-102',
    fullscreen: 'bg-black border-none shadow-none p-0 m-0 h-screen w-screen rounded-none'
  };

  const buttonThemes = {
    neon: 'bg-gradient-to-r from-purple-500 to-pink-500 border-purple-400 shadow-purple-500/50 hover:shadow-purple-500/70 hover:from-purple-600 hover:to-pink-600',
    dark: 'bg-gray-800 border-gray-600 hover:bg-gray-700 hover:border-gray-500 shadow-gray-800/50 hover:shadow-gray-600/50',
    compact: 'bg-white/10 border-white/30 hover:bg-white/20 hover:border-white/50 shadow-white/20 hover:shadow-white/30',
    fullscreen: 'bg-emerald-500/90 border-emerald-400 hover:bg-emerald-600 shadow-emerald-500/50 text-black font-black'
  };

  // Simplified broker connection (demo)
  const connectBroker = (broker) => {
    setActiveBroker(broker);
    setBrokersConnected(prev => ({ ...prev, [broker]: true }));
    setRealBalance(broker === 'mt4' ? '$2,450' : '₹85,230');
    setStatus(`${broker.toUpperCase()} 🟢 Connected`);
  };

  const startTrading = () => {
    if (!activeBroker) return alert('Connect broker first!');
    setIsBotActive(!isBotActive);
  };

  const addPosition = () => {
    setPositions(prev => [{
      id: Date.now(),
      pair: pairMode === 'auto' ? 'AUTO-' + pairs[Math.floor(Math.random() * pairs.length)] : selectedPair,
      broker: activeBroker?.toUpperCase() || 'DEMO',
      side: 'LONG',
      sl: '30 pips',
      tp: '60 pips',
      pnl: '+₹1,850',
      time: new Date().toLocaleTimeString()
    }, ...prev.slice(0, 8)]);
  };

  useEffect(() => {
    if (isBotActive) {
      const interval = setInterval(addPosition, 10000);
      return () => clearInterval(interval);
    }
  }, [isBotActive]);

  return (
    <div className={`min-h-screen p-4 lg:p-8 ${uiMode === 'fullscreen' ? '' : 'glass rounded-3xl m-4 lg:m-8'}`}>
      {/* UI Mode Selector */}
      {uiMode !== 'fullscreen' && (
        <div className={`mb-8 p-4 rounded-2xl ${themes[uiMode]}`}>
          <div className="flex flex-wrap gap-2 justify-center">
            {['neon', 'dark', 'compact', 'fullscreen'].map(mode => (
              <button
                key={mode}
                onClick={() => setUIMode(mode)}
                className={`px-4 py-2 rounded-xl font-bold text-sm transition-all ${uiMode === mode ? buttonThemes[mode] + ' scale-105 shadow-lg' : 'bg-white/10 hover:bg-white/20'}`}
              >
                {mode.toUpperCase()}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* HEADER */}
      <div className={`text-center mb-12 ${uiMode === 'fullscreen' ? 'p-8' : 'p-12 rounded-3xl glass mb-12'}`}>
        <h1 className={`text-4xl lg:text-6xl font-black uppercase tracking-widest bg-gradient-to-r from-emerald-400 via-teal-500 to-cyan-400 bg-clip-text text-transparent drop-shadow-2xl ${uiMode === 'neon' ? 'shadow-purple-500/50 animate-pulse' : ''}`}>
          Welcome to JD-Algo
        </h1>
        <p className={`text-xl lg:text-2xl mt-4 font-bold ${uiMode === 'neon' ? 'text-purple-300 shadow-lg' : 'text-teal-300'}`}>
          4K+ Live Trading • 1:2 Risk • Multi-Broker
        </p>
      </div>

      <div className={`max-w-7xl mx-auto grid ${uiMode === 'compact' ? 'grid-cols-1 gap-4' : 'grid-cols-1 lg:grid-cols-3 gap-8 mb-16'}`}>
        {/* Brokers */}
        <div className={`${themes[uiMode]} p-6 lg:p-8 rounded-3xl`}>
          <h3 className={`text-2xl lg:text-3xl font-black mb-8 text-center uppercase tracking-wider ${uiMode === 'neon' ? 'bg-gradient-to-r from-orange-400 to-red-400 bg-clip-text text-transparent shadow-lg' : ''}`}>
            🔌 Brokers
          </h3>
          
          <div className="space-y-4">
            <button 
              onClick={() => connectBroker('angel')}
              className={`${buttonThemes[uiMode]} w-full py-5 px-6 rounded-2xl font-bold text-lg shadow-xl transition-all border-2 ${brokersConnected.angel ? 'ring-4 ring-emerald-500/30 scale-105' : ''}`}
            >
              🇮🇳 AngelOne {brokersConnected.angel && '🟢'}
            </button>
            
            <button 
              onClick={() => connectBroker('dhan')}
              className={`${buttonThemes[uiMode]} w-full py-5 px-6 rounded-2xl font-bold text-lg shadow-xl transition-all border-2 ${brokersConnected.dhan ? 'ring-4 ring-emerald-500/30 scale-105' : ''}`}
            >
              🇮🇳 Dhan {brokersConnected.dhan && '🟢'}
            </button>
            
            <button 
              onClick={() => connectBroker('mt4')}
              className={`${buttonThemes[uiMode]} w-full py-5 px-6 rounded-2xl font-bold text-lg shadow-xl transition-all border-2 ${brokersConnected.mt4 ? 'ring-4 ring-emerald-500/30 scale-105' : ''}`}
            >
              💱 MT4/MT5 {brokersConnected.mt4 && '🟢'}
            </button>
          </div>
          
          {activeBroker && (
            <div className={`mt-8 p-6 rounded-2xl border-4 border-emerald-400/50 bg-emerald-500/10 text-center ${uiMode === 'neon' ? 'shadow-emerald-500/30 animate-pulse' : ''}`}>
              <div className="text-2xl font-black text-emerald-400">{activeBroker.toUpperCase()}</div>
              <div className="text-lg font-bold mt-2">ACTIVE 🟢</div>
            </div>
          )}
        </div>

        {/* Pair Selection + Control */}
        <div className={`${themes[uiMode]} p-6 lg:p-12 rounded-3xl col-span-1 lg:col-span-2`}>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
            {/* Balance */}
            <div className={`text-center p-8 rounded-3xl ${uiMode === 'neon' ? 'bg-gradient-to-br from-purple-500/20 to-pink-500/20 border-purple-500/40 shadow-purple-500/30' : 'bg-white/5 border-white/20 shadow-lg'}`}>
              <div className="text-4xl lg:text-5xl font-black text-emerald-400 mb-4 drop-shadow-lg">{realBalance}</div>
              <div className="text-xl font-bold opacity-90">REAL BALANCE</div>
            </div>
            
            {/* Pair Mode */}
            <div className={`p-8 rounded-3xl ${uiMode === 'neon' ? 'bg-gradient-to-br from-blue-500/20 to-indigo-500/20 border-blue-500/40 shadow-blue-500/30' : 'bg-white/5 border-white/20 shadow-lg'}`}>
              <div className="text-lg font-bold mb-4 text-center">🎯 Pair Mode</div>
              <div className="flex gap-3">
                <button 
                  onClick={() => setPairMode('auto')}
                  className={`flex-1 py-4 px-6 rounded-xl font-bold transition-all ${pairMode === 'auto' ? `${buttonThemes[uiMode]} shadow-lg scale-105` : 'bg-white/10 hover:bg-white/20'}`}
                >
                  🔄 Auto Scan
                </button>
                <button 
                  onClick={() => setPairMode('manual')}
                  className={`flex-1 py-4 px-6 rounded-xl font-bold transition-all ${pairMode === 'manual' ? `${buttonThemes[uiMode]} shadow-lg scale-105` : 'bg-white/10 hover:bg-white/20'}`}
                >
                  👆 Manual
                </button>
              </div>
              
              {pairMode === 'manual' && (
                <select 
                  value={selectedPair}
                  onChange={e => setSelectedPair(e.target.value)}
                  className={`w-full mt-4 p-4 rounded-xl bg-white/20 border-2 border-white/40 font-bold text-lg focus:border-emerald-400 focus:outline-none ${uiMode === 'neon' ? 'shadow-blue-500/30' : ''}`}
                >
                  {pairs.map(pair => (
                    <option key={pair} value={pair}>{pair}</option>
                  ))}
                </select>
              )}
            </div>
            
            {/* Status */}
            <div className={`p-8 rounded-3xl col-span-1 md:col-span-2 lg:col-span-1 text-center ${uiMode === 'neon' ? 'bg-gradient-to-br from-yellow-500/20 to-orange-500/20 border-yellow-500/40 shadow-yellow-500/30' : 'bg-white/5 border-white/20 shadow-lg'}`}>
              <div className={`text-3xl lg:text-4xl font-black mb-4 ${uiMode === 'neon' ? 'bg-gradient-to-r from-yellow-400 to-orange-400 bg-clip-text text-transparent drop-shadow-lg' : 'text-yellow-400'}`}>
                {status}
              </div>
              <div className="text-xl font-bold opacity-90">SL: 30p | TP: 60p | 1:2</div>
            </div>
          </div>

          {/* START BUTTON */}
          <div className="text-center">
            <button 
              onClick={startTrading}
              disabled={!activeBroker}
              className={`px-16 py-10 lg:px-24 lg:py-12 rounded-4xl font-black text-2xl lg:text-3xl uppercase tracking-widest shadow-2xl mx-auto block transition-all duration-300 ${
                isBotActive
                  ? `${buttonThemes[uiMode]} w-full lg:w-auto border-4 shadow-2xl shadow-emerald-500/60 animate-pulse scale-105 ring-4 ring-emerald-500/50`
                  : (!activeBroker 
                      ? 'bg-gray-600/50 cursor-not-allowed opacity-50 border-gray-500/50' 
                      : `${buttonThemes[uiMode]} w-full lg:w-auto border-2 hover:scale-110 hover:shadow-2xl hover:shadow-emerald-500/70`
                    )
              }`}
            >
              {isBotActive ? '🟢 LIVE TRADING ACTIVE' : '🚀 START REAL TRADING'}
            </button>
          </div>
        </div>
      </div>

      {/* Positions */}
      <div className="max-w-7xl mx-auto">
        <div className={`${themes[uiMode]} p-8 lg:p-16 rounded-4xl border-2`}>
          <h3 className={`text-4xl lg:text-6xl font-black mb-12 text-center uppercase tracking-widest bg-gradient-to-r from-emerald-400 via-teal-500 to-cyan-400 bg-clip-text text-transparent drop-shadow-2xl ${uiMode === 'neon' ? 'shadow-emerald-500/50 animate-pulse' : ''}`}>
            📈 Live Positions
          </h3>
          
          {positions.length === 0 ? (
            <div className={`text-center py-24 rounded-3xl ${uiMode === 'neon' ? 'bg-gradient-to-br from-gray-900/50 to-black/50 border border-white/20 shadow-2xl shadow-black/50' : 'bg-white/5 border-white/20'}`}>
              <div className={`text-4xl lg:text-6xl mb-8 ${uiMode === 'neon' ? 'text-purple-400 shadow-lg animate-pulse' : 'text-gray-400'}`}>
                No Active Trades
              </div>
              <div className="text-2xl opacity-75">Connect broker → Start trading</div>
            </div>
          ) : (
            <div className={`grid ${uiMode === 'compact' ? 'grid-cols-1 gap-4' : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 lg:gap-8'}`}>
              {positions.map(pos => (
                <div key={pos.id} className={`${themes[uiMode]} group p-6 lg:p-10 rounded-3xl border hover:scale-105 hover:shadow-2xl transition-all duration-300 cursor-pointer backdrop-blur-xl hover:border-emerald-400/50`}>
                  <div className="flex justify-between items-start mb-6 pb-6 border-b border-white/20">
                    <div>
                      <div className={`text-2xl lg:text-3xl font-black mb-2 ${uiMode === 'neon' ? 'bg-gradient-to-r from-emerald-400 to-teal-400 bg-clip-text text-transparent shadow-lg' : ''}`}>
                        {pos.pair}
                      </div>
                      <div className={`text-lg font-bold px-4 py-2 rounded-full inline-block ${uiMode === 'neon' ? 'bg-gradient-to-r from-purple-500/30 to-pink-500/30 border border-purple-400/50 shadow-purple-400/30' : 'bg-white/10 border-white/30'}`}>
                        {pos.broker}
                      </div>
                    </div>
                    <button 
                      onClick={() => {}}
                      className="opacity-0 group-hover:opacity-100 p-4 bg-red-500/60 hover:bg-red-600 rounded-3xl transition-all shadow-xl ml-4 font-bold text-xl shadow-red-500/40 hover:shadow-red-500/60 hover:scale-110"
                    >
                      ✕
                    </button>
                  </div>
                  
                  <div className="space-y-4 text-xl">
                    <div className={`font-black text-3xl ${pos.side === 'LONG' ? 'text-emerald-400 shadow-emerald-500/50' : 'text-red-400 shadow-red-500/50'}`}>
                      {pos.side}
                    </div>
                    <div className="grid grid-cols-2 gap-4 text-lg">
                      <div className="flex justify-between">
                        <span>SL:</span>
                        <span className="font-mono text-green-400 font-bold">30 pips</span>
                      </div>
                      <div className="flex justify-between">
                        <span>TP:</span>
                        <span className="font-mono text-blue-400 font-bold">60 pips</span>
                      </div>
                    </div>
                    <div className={`text-2xl font-black p-4 rounded-2xl text-center ${pos.pnl.includes('+') ? 'bg-emerald-500/20 border-emerald-400/50 shadow-emerald-400/30' : 'bg-red-500/20 border-red-400/50 shadow-red-400/30'}`}>
                      {pos.pnl}
                    </div>
                    <div className="text-lg opacity-80 font-mono">{pos.time}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* FOOTER */}
      <footer className={`${themes[uiMode]} max-w-7xl mx-auto mt-20 p-12 rounded-4xl text-center border-2 ${uiMode === 'neon' ? 'shadow-2xl shadow-teal-500/30 border-teal-500/40' : 'border-white/20 shadow-xl'}`}>
        <div className={`text-3xl lg:text-5xl font-black uppercase tracking-widest bg-gradient-to-r from-teal-400 via-emerald-400 to-teal-500 bg-clip-text text-transparent drop-shadow-2xl mb-8 ${uiMode === 'neon' ? 'animate-pulse shadow-teal-500/50' : ''}`}>
          Powered by Xyca Technologies Private Limited
        </div>
        <p className={`text-xl lg:text-2xl opacity-90 font-bold ${uiMode === 'neon' ? 'shadow-lg tracking-wider' : ''}`}>
          JD-Algo • Live Trading • 1:2 Risk Reward • All 4K+ Pairs
        </p>
      </footer>
    </div>
  );
}

export default App;
